# PowerShell completion for magus
# Generated by `magus completion powershell`. Source from your PowerShell profile:
#   magus completion powershell | Out-String | Invoke-Expression
#
# Or persist it:
#   magus completion powershell >> $PROFILE

$__magus_scriptblock = {
    param($wordToComplete, $commandAst, $cursorPosition)

    $subcommands = 'ls', 'graph', 'describe', 'run', 'x', 'affected',
                   'mage', 'version', 'help', 'completion', 'doctor'
    $verbs       = 'ls', 'build', 'test', 'lint', 'format', 'clean',
                   'generate', 'ci'
    $shells      = 'bash', 'zsh', 'fish', 'powershell'
    $affectedFlags = '--explain', '--plan', '--bisect', '--base', '--stdin', '--graph'

    # Tokenize the command line (splits on whitespace, respects quotes via CommandAst).
    $tokens = @($commandAst.CommandElements | ForEach-Object { $_.ToString() })
    $tokenCount = $tokens.Count

    # Nothing beyond `magus` yet -> complete a subcommand.
    if ($tokenCount -le 1) {
        return $subcommands |
            Where-Object { $_ -like "$wordToComplete*" } |
            ForEach-Object {
                [System.Management.Automation.CompletionResult]::new(
                    $_, $_, 'ParameterValue', $_)
            }
    }

    $cmd = $tokens[1]

    function Get-MagusProjects {
        try { & magus ls -o name 2>$null } catch { @() }
    }

    switch ($cmd) {
        'run' {
            if ($tokenCount -le 2 -or ($tokenCount -eq 3 -and $wordToComplete -ne '')) {
                # Second token: the verb.
                return $verbs |
                    Where-Object { $_ -like "$wordToComplete*" } |
                    ForEach-Object {
                        [System.Management.Automation.CompletionResult]::new(
                            $_, $_, 'ParameterValue', $_)
                    }
            }
            return Get-MagusProjects |
                Where-Object { $_ -like "$wordToComplete*" } |
                ForEach-Object {
                    [System.Management.Automation.CompletionResult]::new(
                        $_, $_, 'ParameterValue', $_)
                }
        }
        'affected' {
            if ($wordToComplete.StartsWith('-')) {
                return $affectedFlags |
                    Where-Object { $_ -like "$wordToComplete*" } |
                    ForEach-Object {
                        [System.Management.Automation.CompletionResult]::new(
                            $_, $_, 'ParameterName', $_)
                    }
            }
            if ($tokenCount -le 2 -or ($tokenCount -eq 3 -and $wordToComplete -ne '')) {
                return $verbs |
                    Where-Object { $_ -like "$wordToComplete*" } |
                    ForEach-Object {
                        [System.Management.Automation.CompletionResult]::new(
                            $_, $_, 'ParameterValue', $_)
                    }
            }
        }
        'describe' {
            return Get-MagusProjects |
                Where-Object { $_ -like "$wordToComplete*" } |
                ForEach-Object {
                    [System.Management.Automation.CompletionResult]::new(
                        $_, $_, 'ParameterValue', $_)
                }
        }
        'x' {
            return Get-MagusProjects |
                Where-Object { $_ -like "$wordToComplete*" } |
                ForEach-Object {
                    [System.Management.Automation.CompletionResult]::new(
                        $_, $_, 'ParameterValue', $_)
                }
        }
        'completion' {
            if ($tokenCount -le 2 -or ($tokenCount -eq 3 -and $wordToComplete -ne '')) {
                return $shells |
                    Where-Object { $_ -like "$wordToComplete*" } |
                    ForEach-Object {
                        [System.Management.Automation.CompletionResult]::new(
                            $_, $_, 'ParameterValue', $_)
                    }
            }
        }
        'graph' {
            $flags = '-upstream', '-lang', '-depth', '-root', '-o', '-output'
            return $flags |
                Where-Object { $_ -like "$wordToComplete*" } |
                ForEach-Object {
                    [System.Management.Automation.CompletionResult]::new(
                        $_, $_, 'ParameterName', $_)
                }
        }
    }
}

Register-ArgumentCompleter -CommandName magus -Native -ScriptBlock $__magus_scriptblock
Register-ArgumentCompleter -CommandName mgs   -Native -ScriptBlock $__magus_scriptblock
